   117	static status_t FLEXIO_I2C_MasterTransferInitStateMachine(FLEXIO_I2C_Type *base,
   118	                                                          flexio_i2c_master_handle_t *handle,
   119	                                                          flexio_i2c_master_transfer_t *xfer)
